/**
 * Document Download Route
 *
 * Serves uploaded document files via a short-lived signed token.
 * Used by Custom API webhooks to download files for extraction.
 *
 * GET /api/documents/:documentId/download?token=<signed-jwt>
 *
 * The token is generated by the extraction worker and is valid for 15 minutes.
 * It contains the documentId and tenantId — no user session required.
 */

import { Router, type Request, type Response } from 'express';
import path from 'path';
import { getLazyModel } from '../db/index.js';
import type { ISearchDocument } from '@agent-platform/database';
import { downloadDocumentContent } from '../services/ingestion/download-document.js';
import { getConfig } from '../config/index.js';
import { createLogger } from '@abl/compiler/platform';
import crypto from 'crypto';

const logger = createLogger('document-download');
const SearchDocument = getLazyModel<ISearchDocument>('SearchDocument');

const router: ReturnType<typeof Router> = Router();

export const DOWNLOAD_TOKEN_EXPIRY_MS = 15 * 60 * 1000; // 15 minutes

export interface DownloadTokenPayload {
  documentId: string;
  tenantId: string;
  exp: number;
}

export function isValidDownloadTokenPayload(value: unknown): value is DownloadTokenPayload {
  if (!value || typeof value !== 'object') return false;
  const candidate = value as Record<string, unknown>;
  return (
    typeof candidate.documentId === 'string' &&
    candidate.documentId.trim().length > 0 &&
    typeof candidate.tenantId === 'string' &&
    candidate.tenantId.trim().length > 0 &&
    typeof candidate.exp === 'number' &&
    Number.isFinite(candidate.exp)
  );
}

export function safeContentType(value: unknown): string {
  if (typeof value !== 'string' || /[\r\n]/.test(value)) {
    return 'application/octet-stream';
  }
  return value.includes('/') ? value : 'application/octet-stream';
}

export function safeAttachmentFileName(value: unknown, fallback: string): string {
  const raw = typeof value === 'string' ? value : fallback;
  const sanitized = raw.replace(/[\r\n"\\/]/g, '_').trim();
  return sanitized.length > 0 ? sanitized.slice(0, 180) : fallback;
}

/**
 * Generate a signed download token for a document using HMAC.
 * No external JWT library needed — uses crypto.createHmac.
 */
export function generateDownloadToken(documentId: string, tenantId: string): string {
  const config = getConfig();
  const exp = Date.now() + DOWNLOAD_TOKEN_EXPIRY_MS;
  const payload: DownloadTokenPayload = { documentId, tenantId, exp };
  const data = JSON.stringify(payload);
  const signature = crypto.createHmac('sha256', config.jwt.secret).update(data).digest('hex');
  const token = Buffer.from(data).toString('base64url') + '.' + signature;
  return token;
}

/**
 * Generate a non-expiring download token for persistent storage on documents.
 * Used for design-time access (Studio browse, canonical metadata source_url).
 * Runtime citations generate their own click-limited or time-limited tokens.
 * exp=0 signals "no TTL" — verifyDownloadToken skips expiry check for these.
 */
export function generatePermanentDownloadToken(documentId: string, tenantId: string): string {
  const config = getConfig();
  const payload: DownloadTokenPayload = { documentId, tenantId, exp: 0 };
  const data = JSON.stringify(payload);
  const signature = crypto.createHmac('sha256', config.jwt.secret).update(data).digest('hex');
  const token = Buffer.from(data).toString('base64url') + '.' + signature;
  return token;
}

/**
 * Verify a download token.
 */
function verifyDownloadToken(token: string): DownloadTokenPayload | null {
  try {
    const config = getConfig();
    const parts = token.split('.');
    if (parts.length !== 2) return null;

    const [dataB64, signature] = parts;
    const data = Buffer.from(dataB64, 'base64url').toString();
    const expectedSig = crypto.createHmac('sha256', config.jwt.secret).update(data).digest('hex');

    // Timing-safe comparison to prevent timing attacks
    if (signature.length !== expectedSig.length) return null;
    const sigBuffer = Buffer.from(signature, 'hex');
    const expectedBuffer = Buffer.from(expectedSig, 'hex');
    if (!crypto.timingSafeEqual(sigBuffer, expectedBuffer)) return null;

    const payload = JSON.parse(data) as unknown;
    if (!isValidDownloadTokenPayload(payload)) return null;
    // exp=0 means permanent token (no TTL) — skip expiry check
    if (payload.exp !== 0 && Date.now() > payload.exp) return null;

    return payload;
  } catch {
    return null;
  }
}

/**
 * Build the download URL for a document.
 *
 * SEARCH_AI_PUBLIC_URL should include the ingress prefix path, e.g.:
 *   https://agents-dev.kore.ai/api/search-ai
 *
 * The ingress rewrites /api/search-ai/(.*) → /api/$1 on the pod,
 * so the public URL is: {SEARCH_AI_PUBLIC_URL}/documents/{id}/download?token=...
 * which reaches the pod at: /api/documents/{id}/download?token=...
 */
export function buildDownloadUrl(documentId: string, token: string, reqHost?: string): string {
  const publicUrl = process.env.SEARCH_AI_PUBLIC_URL;
  if (publicUrl) {
    return `${publicUrl}/documents/${documentId}/download?token=${token}`;
  }
  const baseUrl =
    process.env.SEARCH_AI_URL || (reqHost ? `http://${reqHost}` : 'http://localhost:3113');
  return `${baseUrl}/api/documents/${documentId}/download?token=${token}`;
}

/**
 * GET /api/documents/:documentId/download?token=<signed-token>
 *
 * Downloads the document file. Requires a valid signed token.
 * No session/cookie auth — the token itself authorizes the download.
 */
router.get('/api/documents/:documentId/download', async (req: Request, res: Response) => {
  try {
    const { documentId } = req.params;
    const token = typeof req.query.token === 'string' ? req.query.token : '';

    if (!token) {
      res.status(401).json({ error: 'Download token required' });
      return;
    }

    const decoded = verifyDownloadToken(token);
    if (!decoded) {
      res.status(401).json({ error: 'Invalid or expired download token' });
      return;
    }

    if (decoded.documentId !== documentId) {
      res.status(403).json({ error: 'Token does not match document' });
      return;
    }

    const document = await SearchDocument.findOne({
      _id: documentId,
      tenantId: decoded.tenantId,
    }).lean();

    if (!document) {
      res.status(404).json({ error: 'Document not found' });
      return;
    }

    if (!document.sourceUrl) {
      res.status(404).json({ error: 'Document has no source file' });
      return;
    }

    logger.info('Serving document download', {
      documentId,
      tenantId: decoded.tenantId,
    });

    const contentType = document.contentType || 'application/octet-stream';
    const fileName = document.originalReference || `document-${documentId}`;

    // Serve inline so documents open in the browser (e.g. Chrome's PDF viewer)
    // instead of triggering a file download.
    const sourceUrl = document.sourceUrl;

    if (sourceUrl.startsWith('/uploads/') || sourceUrl.startsWith('file://')) {
      // Local file — use res.sendFile() which supports Accept-Ranges (byte
      // range requests). Chrome's PDF viewer REQUIRES range support to display
      // inline — without it, Chrome downloads instead of displaying.
      const config = getConfig();
      let filePath: string;

      if (sourceUrl.startsWith('file://')) {
        filePath = sourceUrl.slice('file://'.length);
      } else {
        const basePath = path.resolve(config.storage?.basePath || './uploads');
        const relativePath = sourceUrl.substring('/uploads/'.length);
        filePath = path.join(basePath, relativePath);
      }

      res.setHeader('Content-Type', contentType);
      res.setHeader('Content-Disposition', `inline; filename="${encodeURIComponent(fileName)}"`);
      res.setHeader('X-Content-Type-Options', 'nosniff');
      res.sendFile(filePath, (err) => {
        if (err && !res.headersSent) {
          logger.error('Document file send error', {
            error: err instanceof Error ? err.message : String(err),
            filePath,
          });
          res.status(404).json({ error: 'Document file not found' });
        }
      });
      return;
    }

    // S3 or HTTP — download to buffer and send inline
    const fileBuffer = await downloadDocumentContent(sourceUrl);

    res.setHeader('Content-Type', contentType);
    res.setHeader('Content-Disposition', `inline; filename="${encodeURIComponent(fileName)}"`);
    res.setHeader('X-Content-Type-Options', 'nosniff');
    res.setHeader('Content-Length', fileBuffer.length);
    // This endpoint serves token-authorized binary document bytes as an attachment, never rendered HTML.
    res.send(fileBuffer); // nosemgrep: javascript.express.security.audit.xss.direct-response-write.direct-response-write
  } catch (error) {
    const msg = error instanceof Error ? error.message : String(error);
    logger.error('Document download failed', { error: msg, documentId: req.params.documentId });
    res.status(500).json({ error: 'Failed to serve document' });
  }
});

export default router;
